(function () {
  if (typeof window === 'undefined' || typeof window.jQuery === 'undefined') {
    return;
  }

  var $ = window.jQuery;

  function buildList(container) {
    var html = $('<ul class="ui-timepicker-list" role="listbox"></ul>');
    var minutes = ['00', '10', '20', '30', '40', '50'];
    for (var h = 0; h < 24; h++) {
      for (var m = 0; m < minutes.length; m++) {
        var value = (h < 10 ? '0' + h : String(h)) + ':' + minutes[m];
        html.append('<li class=\"ui-timepicker-time\" role=\"option\" data-time=\"' + value + '\">' + value + '</li>');
      }
    }

    var wrap = $('<div class="ui-timepicker-wrapper" style="display:none;"></div>');
    wrap.append(html);
    container.after(wrap);
    return wrap;
  }

  function closeAll() {
    $('.ui-timepicker-wrapper').hide();
  }

  $(document).on('click', function (e) {
    if (!$(e.target).closest('.ui-timepicker-wrapper, .timepicker').length) {
      closeAll();
    }
  });

  $.fn.timepicker = function () {
    return this.each(function () {
      var $input = $(this);
      if ($input.data('sensorium-timepicker')) {
        return;
      }
      var $panel = buildList($input);
      $input.attr('autocomplete', 'off').addClass('timepicker');

      $input.on('focus click', function () {
        closeAll();
        $panel.show();
      });

      $panel.on('click', 'li', function () {
        var v = $(this).data('time');
        $input.val(v);
        $panel.hide();
      });

      $input.data('sensorium-timepicker', true);
    });
  };

})();
